const topics = [
  { topic: "مهریه چیست و چه اهمیتی در ازدواج دارد", keyword: "مهریه" },
  { topic: "انواع مهریه در قانون ایران", keyword: "انواع مهریه" },
  { topic: "نحوه مطالبه و وصول مهریه از طریق دادگاه", keyword: "مطالبه مهریه" },
  { topic: "مهریه عندالمطالبه و عندالاستطاعه چه تفاوتی دارند", keyword: "مهریه عندالمطالبه" },
  { topic: "اجرای مهریه از طریق اجرای ثبت اسناد", keyword: "اجرای مهریه" },
  { topic: "حق حبس زن و رابطه آن با مهریه", keyword: "حق حبس مهریه" },
  { topic: "مهریه در صورت فوت شوهر چه می‌شود", keyword: "مهریه بعد از فوت" },
  { topic: "تعدیل و کاهش مهریه آیا ممکن است", keyword: "کاهش مهریه" },
  { topic: "مهریه و طلاق تکلیف مهریه هنگام جدایی", keyword: "مهریه و طلاق" },
  { topic: "زندان مهریه و قانون محکومیت های مالی", keyword: "زندان مهریه" },
  { topic: "نحوه توافق بر سر مهریه قبل از ازدواج", keyword: "توافق مهریه" },
  { topic: "بخشش مهریه و شرایط قانونی آن", keyword: "بخشش مهریه" },
  { topic: "مهریه در ازدواج موقت چگونه است", keyword: "مهریه ازدواج موقت" },
  { topic: "وکیل مهریه چرا برای مطالبه مهریه به وکیل نیاز داریم", keyword: "وکیل مهریه همدان" },
  { topic: "محاسبه مهریه به نرخ روز و شاخص تورم", keyword: "محاسبه مهریه به نرخ روز" }
];

const counter = $getWorkflowStaticData('global');
let index = counter.topicIndex || 0;

if (index >= topics.length) {
  index = 0;
}

const pick = topics[index];

counter.topicIndex = index + 1;

return [{ json: { topic: pick.topic, keyword: pick.keyword, current_index: index } }];

// پاسخ Claude رو از هر فرمتی که باشه استخراج کن
const data = $('Message a model').first().json;
let raw = '';

if (data.content && Array.isArray(data.content)) {
  raw = data.content[0].text;
} else if (data.output) {
  raw = data.output;
} else if (data.text) {
  raw = data.text;
} else if (data.message && data.message.content) {
  raw = data.message.content[0].text;
} else {
  raw = JSON.stringify(data);
}

function getPart(label, next) {
  let start = raw.indexOf('===' + label + '===');
  if (start === -1) return '';
  start = start + ('===' + label + '===').length;
  let end = next ? raw.indexOf('===' + next + '===') : raw.length;
  if (end === -1) end = raw.length;
  return raw.substring(start, end).trim();
}

let title = getPart('TITLE', 'CONTENT');
let content = getPart('CONTENT', 'KEYWORD');
let keyword = getPart('KEYWORD', 'META');
let meta = getPart('META', null);

// فالبک اگه پارس نشد
const topicData = $('Code in JavaScript1').first().json;
if (!title) title = topicData.topic;
if (!keyword) keyword = topicData.keyword;
if (!meta) meta = title;
if (!content) throw new Error('مقاله تولید نشد - خروجی Claude خالی بود');

return [{
  json: {
    title: title,
    content: content,
    focus_keyword: keyword,
    meta_description: meta
  }
}];

